scwin.ondataload = async function (e) {
  let dltStr = "dlt_commonCodeZZ609"; // ZZ609 코드의 dataList
  let dlt = $c.gus.object($p, dltStr);
  $c.gus.copy($p, dltStr, "dlt_commonCodeZZ609_1", true); // dlt_commonCodeZZ609_1 으로 dataList 을 복사
  $c.gus.copy($p, dltStr, "dlt_commonCodeZZ609_2", true);
  let dlt2 = $c.gus.object($p, "dlt_commonCodeZZ609_1"); // 객체화
  let dlt3 = $c.gus.object($p, "dlt_commonCodeZZ609_2"); // 객체화

  // RC 삭제 예정
  $c.data.dataListFilter($p, dlt2, "fltrCd3 == 'AA'");
  $c.data.dataListFilter($p, dlt3, "fltrCd3 == 'RC'");
  rentMakerCd_Normal.setNodeSet("data:dlt_commonCodeZZ609_1", "cdNm", "cd"); // selectBox 에 새로운 데이터리스트로 매핑
  MakerCd_Rent.setNodeSet("data:dlt_commonCodeZZ609_2", "cdNm", "cd"); // selectBox 에 새로운 데이터리스트로 매핑
};
