//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
  // 장비모델ID가 유효하지 않은데도 저장하는 경우
  let vEqModelCdValChk = scwin.txt_eqModelCdValChk;
  let vSaveType = scwin.txt_saveType; // 저장타입
  let vRowDelStat = scwin.txt_rowDelStat; //삭제 상태
  let vEqClsCd = acb_eqClsCd.getValue();
  let vRowStatus = ds_eqmodel.getRowStatus(ds_eqmodel.getRowPosition());

  // 필수항목 체크
  let ret = await $c.gus.cfValidate($p, [chkRegistInfo]);
  if (!ret) {
    return false;
  }

  // 장비모델코드, 장비모델명 체크 	
  let vEqModelCd = ed_eqModelCd.getValue().trimAll();
  if (vRowStatus == 'C') {
    //렌터카 장비모델 중복 체크 	
    if (vEqClsCd == "RV" && vEqModelCdValChk != "0") {
      await $c.win.alert($p, "렌터카장비모델 중복확인을 하시기 바랍니다.");
      scwin.f_openEqModelCdDup();
      return;
    }
  }

  //변경한 데이터가 있는지 체크한다. 	
  if (ds_eqmodel.getModifiedIndex().length > 0 == false) {
    await $c.win.alert($p, "변경된 사항이 없습니다.");
    return;
  }
  if ((await $c.win.confirm($p, "저장하시겠습니까?")) == true) {
    scwin.pos_eqModel = ds_eqmodel.getRowPosition();
    $c.sbm.execute($p, sbm_saveEqModel);
  }
  //$c.gus.cfDisableBtnOnly([bAddRow, bUpdateRow, bDeleteRow]);
};
scwin.f_downExcelSheet = async function () {
  let cntRow = ds_eqmodel.getRowCount();
  if (cntRow != 0) {
    cfrm = await $c.win.confirm($p, "장비모델목록을 EXCEL로 다운로드 받으시겠습니까?");
    if (cfrm) {
      let fileName = '장비모델목록';
      let sheetTitle = '물류중기목록';
      await $c.data.downloadGridViewExcel($p, gr_eqmodel, {
        fileName: fileName + ".xlsx",
        sheetName: sheetTitle
      });
    }
  } else {
    await $c.win.alert($p, MSG_CM_WRN_002);
  }
};

