scwin.sbm_saveEqModel_submitdone = async function (e) {
  if (e.responseJSON.resultDataSet[0].Code < 0) {
    // scwin.f_Retrieve();
    return;
  }
  let vSaveType = scwin.txt_saveType; // 저장타입

  if (vSaveType == "3") {
    // 장비모델 삭제인 경우
    await $c.win.alert($p, MSG_CM_INF_004); // 성공적으로 삭제 하였습니다	
  } else {
    // 장비모델 등록, 수정인 경우
    await $c.win.alert($p, MSG_CM_INF_001); // 성공적으로 저장하였습니다
  }
  ds_eqmodel.reform();
  scwin.f_Retrieve();
};
scwin.sbm_searchEqmodel_submitdone = async function (e) {
  ds_eqmodel.reform();
  let rowCnt = ds_eqmodel.getRowCount();
  scwin.txt_countRow = rowCnt;
  //조회결과가 0인경우
  if (rowCnt == 0) {
    $c.gus.cfDisableBtn($p, [b_Update, btn_save]);
  } else if (rowCnt > 0) {
    $c.gus.cfDisableBtn($p, [btn_save, b_Cancel]);
  }
  // 조회된 건수를 Grid 왼쪽 하단에 표시한다.
  totalRows.setValue(rowCnt);
  scwin.txt_retrieveYn = "1";
  if (rowCnt == 0) {
    await $c.win.alert($p, "조회된 데이터가 없습니다.");
    ed_qryCntn.focus();
  }
  $c.gus.cfGoPrevPosition($p, gr_eqmodel, scwin.pos_eqModel);
};
scwin.sbm_eqClssCd_submitdone = async function (e) {
  let idx = ds_eqmodel.getRowPosition();
  let vRowStatus = ds_eqmodel.getRowStatus(ds_eqmodel.getRowPosition());
  ds_eqmodel.setCellData(idx, "eqClssCd", scwin.vEqClssCd);
  if (idx >= 0 && ds_eqmodel.getRowStatus(idx) == "R") {
    return;
  }
  if (ds_eqmodel.getRowCount() == 0 || scwin.createItem == "C") {
    acb_eqClssCd.setValue('TG');
  }

  // if(vRowStatus=="C" || vRowStatus=="U"){
  //     if(acb_eqClsCd.getValue() == "RV"){
  //         acb_eqClssCd.setValue("RV");
  //         acb_eqNrmCd.setValue("175");
  //     }
  // }
  debugger;
  if (scwin.vEqClssCdStatus != "C" && ds_eqmodel.getRowCount() != 0) {
    acb_eqClssCd.setValue(scwin.vEqClssCd);
    scwin.vEqClssCdStatus = "";
  } else {
    acb_eqClssCd.setValue(ds_eqClssCd.getCellData(0, "cd"));
    scwin.vEqClssCdStatus = "";
  }
  let vEqClssCd = ds_eqmodel.getCellData(ds_eqmodel.getRowPosition(), "eqClssCd");
  if (acb_eqClssCd.getValue() == "RV") {
    scwin.txt_asetKndCd = "1";
  }
  if (scwin.acb_eqClsCd_changed == true | scwin.acb_eqClssCd_changed == true) {
    scwin.f_eqCodeList(sbm_eqKndCd, "ZZ210", ds_eqClssCd.getCellData(0, 'cd'));
  }
};
